-- JumpHost Database Schema + Sample Data
-- MySQL 5.7+

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

CREATE TABLE IF NOT EXISTS `access_logs` (`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `domain_id` int(10) unsigned NOT NULL, `ip` varchar(45) COLLATE utf8mb4_unicode_ci NOT NULL, `location` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'IPеЅ’е±ћењ°', `isp` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'иїђиђҐе•†', `user_agent` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL, `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (`id`), KEY `idx_domain_id` (`domain_id`), KEY `idx_created_at` (`created_at`), KEY `idx_location` (`location`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `admin_logs` (`id` bigint(20) unsigned NOT NULL AUTO_INCREMENT, `admin_id` int(10) unsigned NOT NULL DEFAULT '0', `username` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '', `ip` varchar(45) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '', `location` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'IPеЅ’е±ћењ°', `domain` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT 'и®їй—®еџџеђЌ', `ua` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL, `action` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '', `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (`id`), KEY `idx_created_at` (`created_at`), KEY `idx_location` (`location`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `admins` (`id` int(10) unsigned NOT NULL AUTO_INCREMENT, `username` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL, `password` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL, `role` enum('super','agent','personal') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'personal' COMMENT 'и§’и‰І', `status` enum('active','disabled') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active' COMMENT 'зЉ¶жЂЃ', `owner_id` int(10) unsigned NOT NULL DEFAULT '0' COMMENT 'е€›е»єиЂ…ID', `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (`id`), UNIQUE KEY `username` (`username`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `domains` (`id` int(10) unsigned NOT NULL AUTO_INCREMENT, `domain` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'з»‘е®љеџџеђЌ', `name` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL, `protocol` enum('http','https') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'https', `target_url` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'з›®ж ‡URL', `template` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '302' COMMENT 'жЁЎжќїеђЌз§°', `status` enum('active','paused') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active', `delay` tinyint(3) unsigned NOT NULL DEFAULT '3', `img_url` text COLLATE utf8mb4_unicode_ci, `site_title` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL, `site_description` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL, `is_show_link` tinyint(1) DEFAULT '1', `remarks` text COLLATE utf8mb4_unicode_ci, `sort_order` int(11) DEFAULT '0', `owner_id` int(10) unsigned NOT NULL DEFAULT '0' COMMENT 'ж‰Ђе±ћз”Ёж€·ID', `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP, `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, PRIMARY KEY (`id`), UNIQUE KEY `uk_domain_protocol` (`domain`,`protocol`), KEY `idx_domain` (`domain`), KEY `idx_status` (`status`), KEY `idx_owner_id` (`owner_id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC;

CREATE TABLE IF NOT EXISTS `ip_cache` (`ip` varchar(45) COLLATE utf8mb4_unicode_ci NOT NULL, `location` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '', `isp` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '', `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, PRIMARY KEY (`ip`), KEY `idx_updated_at` (`updated_at`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `media` (`id` int(10) unsigned NOT NULL AUTO_INCREMENT, `filename` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'ж–‡д»¶еђЌ', `url` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'и®їй—®URL', `lib` enum('random','gallery') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'gallery' COMMENT 'е›ѕеє“з±»ећ‹', `owner_id` int(10) unsigned NOT NULL DEFAULT '0' COMMENT 'дёЉдј иЂ…ID', `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (`id`), KEY `idx_lib` (`lib`), KEY `idx_owner_id` (`owner_id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `settings` (`key` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL, `value` text COLLATE utf8mb4_unicode_ci NOT NULL, PRIMARY KEY (`key`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

